mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT u.users_seq, u.name, u.id, u.role, u.hire_date, u.dept_seq, u.rank_seq, d.dept_name, r.rank_name, CASE u.status WHEN 'ACTIVE' THEN '재직' WHEN 'INACTIVE' THEN '휴직' WHEN 'RETIRE' THEN '퇴사' END as status FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq LEFT JOIN "RANK" r ON u.rank_seq = r.rank_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')
ORDER BY u.users_seq ) a ) WHERE rn BETWEEN #{start} AND #{end}

SELECT COUNT(*) FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')

SELECT COUNT(*) FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')

